-- W1.6 questions batch 843/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aviation-1dfb84e5-moex-00056', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'essay', '短文寫作：（20分）
王陽明說：「吾輩用功，只求日減，不求日增。」這種減法的原
則，頗能減輕現代繁忙窘迫的生活壓力；但是，老子雖然說「為道日
損」，卻也說「為學日益」，對生活所需的知識和技能，則主張要多
學習和增加。所以，人生什麼項目該用「減法」？什麼項目又該用「加
法」？這是一個需要衡量評估的問題。
請以「人生的減法與加法」為題，列舉至少四個自己需要加減
的項目，並加以闡述。（文長不超過 400 字）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00057', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'essay', '作文：（60分）
貝多芬在創作第七號交響曲的諧謔曲，蒐錄了一首古老的奧地
利朝聖詩歌，他以管風琴的某個音作為主線，像織錦般地逐步經營整
首音樂。那個音是 A，整個樂團的樂器都以這個音為準。剛開始時，
這個音聽起來很柔和，然後越來越明顯，最後，銅管聲勢浩大地奏出
一片「顫動的火焰」，這是音樂史上偉大的一刻。
生活的各個領域也是如此，重點是關係整個樂團樂器最初那個
看似不明顯的音。請以貝多芬的創作為借鏡，申述自己生活中「定出
主線，逐步經營」的經驗與見解。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00058', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'single_choice', '下列選項前後對話，成語使用最適當的是：', '["「令尊年高八十，猶然老當益壯。」／「家父身手靈活，真是一馬當先。」", "「貴公司業績能逆勢成長，可賀！可賀！」／「這全仰賴大家上下一心。」", "「你家屋內整理得光耀門楣，真是好看。」／「這一切，都是拙荊的心血。」", "「令公子金榜題名，真是蓬蓽生輝！」／「過獎！過獎！小兒不過是班門弄斧。」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00059', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'single_choice', '「上個世紀結束後我再次離開美濃。當我在困頓、漂泊的午夜中神遊我莊、回顧自我， 慢慢發現，其實我莊植長在我身體之中，有時甚至就坐在額頭，左右了我人生的轉 彎。而且，它是我理解世界的第一個版本，往後的無數次增修，都將依之據之。」 根據上文，有關作者對「我莊」的敘述，最適當的是：', '["近鄉情怯，離家多年後再次返家，對於「我莊」益發思念", "雖遊歷世界多處，但始終未曾發現比「我莊」更美的地方", "曾在離家後的困頓之際想起「我莊」，進而反思其真正涵義", "時時惦記「我莊」，並藉由遠行經驗多次修改「我莊」形象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00060', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'single_choice', '「東方繪畫為主的中國花鳥畫，自古即在其象徵意義上，有更明確的發揮，比如以花 卉為寄寓，作為理想人格的投映。」 下列選項，何者最能呼應上文所述？', '["人面不知何處去，桃花依舊笑春風", "花謝花飛飛滿天，紅消香斷有誰憐", "竹外桃花三兩枝，春江水暖鴨先知", "莫嫌老圃秋容淡，且看黃花晚節香"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00061', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'single_choice', '行文表述時，合宜地運用正向思維與負向思維，接續排列文句，可達到顛覆與反轉 的趣味。如同曾任英國首相的邱吉爾名言：「你有敵人？很好！那說明在你人生中， 你曾為某些事堅持過。」即是善用了「先負轉正」的敘述方式。 下列那個句子的敘述方式最接近上文例句表述的方式？', '["生命是一襲華美的袍，爬滿了蝨子", "你在黑夜獨行，堅定地走出一路山明水秀", "先要了解事實，然後你才能夠隨心所欲的扭曲誤解它", "這個世界如此美好，值得人們為它奮鬥，我只同意後半句"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00062', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'single_choice', '「凡是好人都樂於助人。小郭常常幫助別人，所以小郭是個好人。」以上的推論無效， 因為小郭常助人，可能別有所圖。下列何者也是這種無效的推論？', '["唯有正直的人是君子，所以不正直的人肯定不是君子", "唯有積極踏實者能成功，所以成功者都是積極踏實的", "凡是人都需要飲食。機器人不必飲食，所以機器人不是人", "凡是大丈夫都能屈能伸。阿德能屈能伸，所以阿德是大丈夫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00063', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'single_choice', '齊莊公出獵，有一蟲舉足將搏其輪。問其御曰：「此何蟲也？」對曰：「此所謂螳螂 者也。其為蟲也，知進而不知卻，不量力而輕敵。」莊公曰：「此為人，而必為天下 勇武矣！」迴車而避之，勇武聞之，知所盡死矣。（《淮南子》） 根據上文，齊莊公迴車而避之造成的結果是：', '["不與勇武之士衝突", "勇武之士無所畏懼", "勇武之士欲求明主", "不必遠求勇武之士"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00064', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'single_choice', '「沒有嚐過窮苦，不懂得安逸的好處；沒有感到人生的寂寞，不能了解真愛的價值。 同樣地，未曾有過經驗的孺子，難以了解天真之可貴；老年人所以會和藹可親，也 是因為曾受過了經驗的洗禮。必定要對於人世上萬物萬事全看淡了，然後對於一二 件東西的留戀才會倍見真摯動人。」 根據上文，下列選項何者最接近文意？', '["甘將泥尾隨龜後，尚有雲心在鶴前", "獨當春盡情何限，尚有秋期別未遙", "存亡慣見渾無淚，鄉井難忘尚有心", "群山萬壑赴荊門，生長明妃尚有村"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00065', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'single_choice', '「這並不是說，我想像自己的死不會給人留下遺憾：訃告無疑是會有的；但是，儘管 有哀悼——我並不否認這一點——我看到他人的生活照樣繼續著，依然如故；我看 到他們一如既往地忙於自己的事務，孜孜於他們的消遣，糾纏於他們的煩惱，光顧 同樣的場所、同樣的朋友；一切照舊，任什麼都改變不了他們的生存。」 根據上文，下列選項何者最接近作者對生死的感受？', '["重於泰山，輕於鴻毛", "安時處順，樂在其中", "生不足樂，死不足悲", "淡泊明志，寧靜致遠"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL)
